import torch_npu
import custom_ops_lib as _ops

class ModelNew(nn.Module):
    def __init__(self, num_features: int):
        super().__init__()
        self.num_features = num_features
        self.affine = True
        self.track_running_stats = True
        self.momentum = 0.1
        self.eps = 1e-5

        if self.affine:
            self.weight = nn.Parameter(torch.ones(num_features))
            self.bias = nn.Parameter(torch.zeros(num_features))
        else:
            self.register_parameter('weight', None)
            self.register_parameter('bias', None)

        if self.track_running_stats:
            self.register_buffer('running_mean', torch.zeros(num_features))
            self.register_buffer('running_var', torch.ones(num_features))
        else:
            self.register_buffer('running_mean', None)
            self.register_buffer('running_var', None)

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        # Convert to NPU tensors if not already
        x = x.to('npu')
        rm = self.running_mean.to(x.device)
        rv = self.running_var.to(x.device)
        w = self.weight.to(x.device) if self.weight is not None else torch.ones(self.num_features, device=x.device)
        b = self.bias.to(x.device) if self.bias is not None else torch.zeros(self.num_features, device=x.device)

        result = _ops.ca6k_00329_custom(
            x, rm, rv, w, b,
            self.momentum, self.eps, self.training
        )
        y, batch_mean, batch_var = result[0], result[1], result[2]

        if self.training and self.track_running_stats:
            with torch.no_grad():
                self.running_mean = (1 - self.momentum) * self.running_mean + self.momentum * batch_mean.cpu()
                self.running_var = (1 - self.momentum) * self.running_var + self.momentum * batch_var.cpu()

